),
"Coverage: Payer Type" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'type') AS "type" FROM resources r WHERE r.resourceType = 'Coverage' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.114222.4.11.3591')
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Follow up with Rescreen Within 6 Months" AS (
SELECT * FROM "ServiceRequest: Follow Up Within 6 Months" AS FollowUp WHERE CASE WHEN FollowUp.intent IS NULL AND 'order' IS NULL THEN TRUE WHEN FollowUp.intent IS NULL OR 'order' IS NULL THEN FALSE ELSE FollowUp.intent = 'order' END
),
"Laboratory Test or ECG for Hypertension" AS (
SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: 12 lead EKG panel" UNION SELECT patient_id, resource FROM "ServiceRequest: EKG study" UNION SELECT patient_id, resource FROM "ServiceRequest: Laboratory Tests for Hypertension") AS EKGLab WHERE CASE WHEN fhirpath_text(EKGLab.resource, 'intent') IS NULL AND 'order' IS NULL THEN TRUE WHEN fhirpath_text(EKGLab.resource, 'intent') IS NULL OR 'order' IS NULL THEN FALSE ELSE fhirpath_text(EKGLab.resource, 'intent') = 'order' END
),
"Laboratory Test or ECG for Hypertension Not Ordered" AS (
SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: 12 lead EKG panel (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: EKG study (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Laboratory Tests for Hypertension (servicenotrequested)") AS LabECGNotDone WHERE fhirpath_text(LabECGNotDone.resource, 'extension.url') = 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason' AND in_valueset(LabECGNotDone.resource, 'extension.value', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582')
),
"NonPharmacological Intervention Not Ordered" AS (
SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Lifestyle Recommendation (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Weight Reduction Recommended (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Dietary Recommendations (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Recommendation to Increase Physical Activity (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Referral or Counseling for Alcohol Consumption (servicenotrequested)") AS NonPharmIntervention WHERE fhirpath_text(NonPharmIntervention.resource, 'status') = 'completed' AND in_valueset(NonPharmIntervention.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582')
),
"NonPharmacological Interventions" AS (
