),
"Qualifying Encounter during Measurement Period" AS (
SELECT * FROM "Encounter: Encounter to Screen for Blood Pressure" AS ValidEncounter WHERE CAST(intervalStart(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND CASE WHEN ValidEncounter.status IS NULL AND 'finished' IS NULL THEN TRUE WHEN ValidEncounter.status IS NULL OR 'finished' IS NULL THEN FALSE ELSE ValidEncounter.status = 'finished' END AND NOT fhirpath_bool(ValidEncounter.resource, 'class.where(system=''http://terminology.hl7.org/CodeSystem/v3-ActCode'' and code=''VR'').exists()')
),
"Denominator Exclusions" AS (
