ELECT resource FROM "Observation (us-core-blood-pressure)" AS BloodPressure WHERE intervalContains(fhirpath_text(QualifyingEncounter.resource, 'period'), intervalEnd(CASE WHEN fhirpath_text(BloodPressure.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BloodPressure.resource, 'effective')), '{') THEN fhirpath_text(BloodPressure.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BloodPressure.resource, 'effective'), fhirpath_text(BloodPressure.resource, 'effective'), TRUE, TRUE) END)) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(BloodPressure.resource, 'status')) AND BloodPressure.patient_id = QualifyingEncounter.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(BloodPressure.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BloodPressure.resource, 'effective')), '{') THEN fhirpath_text(BloodPressure.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(BloodPressure.resource, 'effective'), fhirpath_text(BloodPressure.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(BloodPressure.resource, '$.id') ASC NULLS LAST LIMIT 1), 'component.where(code.coding.code = ''8462-4'').valueQuantity.value') AS VARCHAR))
