"Initial Population" AS (
SELECT * FROM "Qualifying Encounter during Measurement Period" AS QualifyingEncounter WHERE EXTRACT(YEAR FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-01-01T00:00:00.000' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = QualifyingEncounter.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 18
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Referral to Alternate or Primary Healthcare Professional for Hypertensive Reading" AS (
SELECT * FROM "ServiceRequest: Referral to Primary Care or Alternate Provider" AS Referral WHERE in_valueset(Referral.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113762.1.4.1047.514') AND CASE WHEN Referral.intent IS NULL AND 'order' IS NULL THEN TRUE WHEN Referral.intent IS NULL OR 'order' IS NULL THEN FALSE ELSE Referral.intent = 'order' END
),
"Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80 and Interventions" AS (
(SELECT patient_id, resource FROM "Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80" AS ElevatedEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Follow up with Rescreen Within 6 Months") AS Twoto6MonthRescreen WHERE CAST(fhirpath_text(Twoto6MonthRescreen.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(Twoto6MonthRescreen.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND Twoto6MonthRescreen.patient_id = ElevatedEncounter.patient_id) AND EXISTS (SELECT 1 FROM (SELECT * FROM "NonPharmacological Interventions") AS NonPharmInterventions WHERE CAST(fhirpath_text(NonPharmInterventions.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(NonPharmInterventions.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND NonPharmInterventions.patient_id = ElevatedEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80" AS ElevatedEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Referral to Alternate or Primary Healthcare Professional for Hypertensive Reading") AS Referral WHERE CAST(fhirpath_text(Referral.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(Referral.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(ElevatedEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND Referral.patient_id = ElevatedEncounter.patient_id))
),
"First Hypertensive Reading Interventions or Referral to Alternate Professional" AS (
(SELECT patient_id, resource FROM "ServiceRequest: Follow Up Within 4 Weeks" AS FourWeekRescreen WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "NonPharmacological Interventions") AS NonPharmInterventionsHTN WHERE CAST(fhirpath_text(FourWeekRescreen.resource, 'authoredOn') AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(fhirpath_text(FourWeekRescreen.resource, 'authoredOn') AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND CAST(fhirpath_text(NonPharmInterventionsHTN.resource, 'authoredOn') AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(fhirpath_text(NonPharmInterventionsHTN.resource, 'authoredOn') AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND CASE WHEN fhirpath_text(FourWeekRescreen.resource, 'intent') IS NULL AND 'order' IS NULL THEN TRUE WHEN fhirpath_text(FourWeekRescreen.resource, 'intent') IS NULL OR 'order' IS NULL THEN FALSE ELSE fhirpath_text(FourWeekRescreen.resource, 'intent') = 'order' END AND NonPharmInterventionsHTN.patient_id = FourWeekRescreen.patient_id)) UNION (SELECT patient_id, resource FROM "Referral to Alternate or Primary Healthcare Professional for Hypertensive Reading")
