),
"Numerator" AS (
(SELECT patient_id, resource FROM "Encounter with Normal Blood Pressure Reading") UNION (SELECT patient_id, resource FROM "Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80 and Interventions") UNION (SELECT patient_id, resource FROM "Encounter with First Hypertensive Reading SBP Greater than or Equal to 130 OR DBP Greater than or Equal to 80 and Interventions") UNION (SELECT patient_id, resource FROM "Encounter with Second Hypertensive Reading SBP 130 to 139 OR DBP 80 to 89 and Interventions") UNION (SELECT patient_id, resource FROM "Encounter with Second Hypertensive Reading SBP Greater than or Equal to 140 OR DBP Greater than or Equal to 90 and Interventions")
),
"Second Hypertensive Reading SBP Greater than or Equal to 140 OR DBP Greater than or Equal to 90 Interventions Declined" AS (
(SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Referral to Primary Care or Alternate Provider (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Follow Up Within 4 Weeks (servicenotrequested)") AS SecondHTN140Over90ReferralFollowUpNotDone WHERE fhirpath_text(SecondHTN140Over90ReferralFollowUpNotDone.resource, 'status') = 'completed' AND in_valueset(SecondHTN140Over90ReferralFollowUpNotDone.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582')) UNION (SELECT patient_id, resource FROM "MedicationRequest: Pharmacologic Therapy for Hypertension (medicationnotrequested)" AS MedicationRequestNotOrdered WHERE MedicationRequestNotOrdered.status = 'completed') UNION (SELECT patient_id, resource FROM "Laboratory Test or ECG for Hypertension Not Ordered") UNION (SELECT patient_id, resource FROM "NonPharmacological Intervention Not Ordered")
),
"Encounter with Order for Hypertension Follow Up Declined by Patient" AS (
(SELECT patient_id, resource FROM "Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80" AS ElevatedBPEncounter WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "ServiceRequest: Referral to Primary Care or Alternate Provider (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Follow Up Within 6 Months (servicenotrequested)") AS ElevatedBPDeclinedInterventions WHERE CAST(fhirpath_text(ElevatedBPDeclinedInterventions.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(ElevatedBPEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(ElevatedBPDeclinedInterventions.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(ElevatedBPEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND fhirpath_text(ElevatedBPDeclinedInterventions.resource, 'status') = 'completed' AND in_valueset(ElevatedBPDeclinedInterventions.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582') AND ElevatedBPDeclinedInterventions.patient_id = ElevatedBPEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with Elevated Blood Pressure Reading SBP 120 to 129 AND DBP less than 80" AS ElevatedBPEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "NonPharmacological Intervention Not Ordered") AS NotOrdered WHERE CAST(fhirpath_text(NotOrdered.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(ElevatedBPEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(NotOrdered.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(ElevatedBPEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND NotOrdered.patient_id = ElevatedBPEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with First Hypertensive Reading SBP Greater than or Equal to 130 OR DBP Greater than or Equal to 80" AS FirstHTNEncounter WHERE EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "ServiceRequest: Follow Up Within 4 Weeks (servicenotrequested)" UNION SELECT patient_id, resource FROM "ServiceRequest: Referral to Primary Care or Alternate Provider (servicenotrequested)") AS FirstHTNDeclinedInterventions WHERE CAST(fhirpath_text(FirstHTNDeclinedInterventions.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(FirstHTNEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(FirstHTNDeclinedInterventions.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(FirstHTNEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND fhirpath_text(FirstHTNDeclinedInterventions.resource, 'status') = 'completed' AND in_valueset(FirstHTNDeclinedInterventions.resource, 'extension.where(url=''http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-doNotPerformReason'').valueCodeableConcept', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1582') AND FirstHTNDeclinedInterventions.patient_id = FirstHTNEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with First Hypertensive Reading SBP Greater than or Equal to 130 OR DBP Greater than or Equal to 80" AS FirstHTNEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "NonPharmacological Intervention Not Ordered") AS NoNonPharm WHERE CAST(fhirpath_text(NoNonPharm.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(FirstHTNEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(NoNonPharm.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(FirstHTNEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND NoNonPharm.patient_id = FirstHTNEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with Second Hypertensive Reading SBP 130 to 139 OR DBP 80 to 89" AS SecondHTNEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Second Hypertensive Reading SBP 130 to 139 OR DBP 80 to 89 Interventions Declined") AS SecondHTNDeclinedInterventions WHERE CAST(fhirpath_text(SecondHTNDeclinedInterventions.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(SecondHTNEncounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(SecondHTNDeclinedInterventions.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(SecondHTNEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND SecondHTNDeclinedInterventions.patient_id = SecondHTNEncounter.patient_id)) UNION (SELECT patient_id, resource FROM "Encounter with Second Hypertensive Reading SBP Greater than or Equal to 140 OR DBP Greater than or Equal to 90" AS SecondHTN140Over90Encounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "Second Hypertensive Reading SBP Greater than or Equal to 140 OR DBP Greater than or Equal to 90 Interventions Declined") AS SecondHTN140Over90DeclinedInterventions WHERE CAST(fhirpath_text(SecondHTN140Over90DeclinedInterventions.resource, 'authoredOn') AS DATE) >= CAST(intervalStart(fhirpath_text(SecondHTN140Over90Encounter.resource, 'period')) AS DATE) AND CAST(fhirpath_text(SecondHTN140Over90DeclinedInterventions.resource, 'authoredOn') AS DATE) <= COALESCE(CAST(intervalEnd(fhirpath_text(SecondHTN140Over90Encounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) AND SecondHTN140Over90DeclinedInterventions.patient_id = SecondHTN140Over90Encounter.patient_id))
),
"Denominator Exceptions" AS (
(SELECT patient_id, resource FROM "Encounter with Medical Reason for Not Obtaining or Patient Declined Blood Pressure Measurement") UNION (SELECT patient_id, resource FROM "Encounter with Order for Hypertension Follow Up Declined by Patient")
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Denominator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exclusions".resource, '$.id')), []) FROM "Denominator Exclusions" WHERE "Denominator Exclusions".patient_id = p.patient_id AND "Denominator Exclusions".resource IS NOT NULL) AS "Denominator Exclusions", (SELECT COALESCE(LIST(json_extract_string("Denominator Exceptions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exceptions".resource, '$.id')), []) FROM "Denominator Exceptions" WHERE "Denominator Exceptions".patient_id = p.patient_id AND "Denominator Exceptions".resource IS NOT NULL) AS "Denominator Exceptions", (SELECT COALESCE(LIST(json_extract_string("Numerator".resource, '$.resourceType') || '/' || json_extract_string("Numerator".resource, '$.id')), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id AND "Numerator".resource IS NOT NULL) AS Numerator FROM _patients p ORDER BY p.patient_id ASC
